/*
 * Segregated free list allocator with:
 * - 4-byte (32-bit) headers and footers (saves space vs 8-byte)
 * - Footers only on free blocks (prev_alloc bit optimization)
 * - 14 segregated free list size classes
 * - Best-fit search within matching class, first-fit in larger classes
 * - Smart realloc with in-place expansion
 * - 8-byte alignment
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

team_t team = {
	"BSCS Bench",
	"BSCS Bench Agent",
	"bscs1",
	"",
	""
};

/* Basic constants */
#define WSIZE       4            /* Header/footer size (bytes) */
#define DSIZE       8            /* Double word / alignment (bytes) */
#define CHUNKSIZE   (1 << 12)    /* Default heap extension (bytes) */
#define MIN_BLOCK   24           /* Minimum block size: hdr(4)+next(8)+prev(8)+ftr(4) */
#define NUM_CLASSES 14           /* Number of segregated free list classes */

#define MAX(x, y) ((x) > (y) ? (x) : (y))

/*
 * Pack size and flag bits into a 32-bit word.
 * Bit 0: allocated.  Bit 1: previous block allocated.
 */
#define PACK(size, flags) ((unsigned int)((size) | (flags)))

/* Read / write a 32-bit word at address p */
#define GET(p)      (*(unsigned int *)(p))
#define PUT(p, val) (*(unsigned int *)(p) = (unsigned int)(val))

/* Extract fields from a header / footer word */
#define GET_SIZE(p)       (GET(p) & ~0x7)
#define GET_ALLOC(p)      (GET(p) & 0x1)
#define GET_PREV_ALLOC(p) (GET(p) & 0x2)

/* Given block ptr bp, compute header and footer addresses */
#define HDRP(bp) ((char *)(bp) - WSIZE)
#define FTRP(bp) ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given block ptr bp, compute next and previous block ptrs */
#define NEXT_BLKP(bp) ((char *)(bp) + GET_SIZE(HDRP(bp)))
#define PREV_BLKP(bp) ((char *)(bp) - GET_SIZE((char *)(bp) - DSIZE))

/* Free block list pointers stored in the payload area */
#define NEXT_FREEP(bp) (*(void **)(bp))
#define PREV_FREEP(bp) (*(void **)((char *)(bp) + sizeof(void *)))

/* Global variables (scalar pointers only — no arrays or structs) */
static char *heap_listp;     /* Prologue block pointer */
static void **seg_lists;     /* Segregated free list heads (array stored in heap) */

/* Internal helper prototypes */
static void *coalesce(void *bp);
static void *extend_heap(size_t bytes);
static void *find_fit(size_t asize);
static void place(void *bp, size_t asize);
static void insert_free(void *bp);
static void remove_free(void *bp);
static int  get_class(size_t size);

/* Heap checker prototypes */
static void checkblock(void *bp);
static void checkheap(bool verbose);
static void printblock(void *bp);

/*
 * get_class - Return the segregated-list index for a given block size.
 */
static int
get_class(size_t size)
{
	if (size <= 32)     return 0;
	if (size <= 64)     return 1;
	if (size <= 128)    return 2;
	if (size <= 256)    return 3;
	if (size <= 512)    return 4;
	if (size <= 1024)   return 5;
	if (size <= 2048)   return 6;
	if (size <= 4096)   return 7;
	if (size <= 8192)   return 8;
	if (size <= 16384)  return 9;
	if (size <= 32768)  return 10;
	if (size <= 65536)  return 11;
	if (size <= 131072) return 12;
	return 13;
}

/*
 * insert_free - Insert bp at the head of the appropriate segregated list (LIFO).
 */
static void
insert_free(void *bp)
{
	int cls = get_class(GET_SIZE(HDRP(bp)));
	void *head = seg_lists[cls];

	NEXT_FREEP(bp) = head;
	PREV_FREEP(bp) = NULL;
	if (head != NULL)
		PREV_FREEP(head) = bp;
	seg_lists[cls] = bp;
}

/*
 * remove_free - Remove bp from its segregated free list.
 */
static void
remove_free(void *bp)
{
	int cls = get_class(GET_SIZE(HDRP(bp)));
	void *prev = PREV_FREEP(bp);
	void *next = NEXT_FREEP(bp);

	if (prev != NULL)
		NEXT_FREEP(prev) = next;
	else
		seg_lists[cls] = next;
	if (next != NULL)
		PREV_FREEP(next) = prev;
}

/*
 * mm_init - Initialize the memory manager.
 *
 * Heap layout after init:
 *   [seg_list heads (NUM_CLASSES * 8)] [pad 4] [prologue hdr 4]
 *   [prologue ftr 4] [epilogue hdr 4]
 */
int
mm_init(void)
{
	size_t heads_bytes = NUM_CLASSES * sizeof(void *);
	size_t init_size = heads_bytes + 4 * WSIZE;
	char *start;

	if ((start = mem_sbrk(init_size)) == (void *)-1)
		return (-1);

	/* Initialize segregated list heads to NULL */
	seg_lists = (void **)start;
	for (int i = 0; i < NUM_CLASSES; i++)
		seg_lists[i] = NULL;

	char *p = start + heads_bytes;
	PUT(p, 0);                           /* Alignment padding */
	PUT(p + WSIZE, PACK(DSIZE, 3));      /* Prologue header: size=8, alloc=1, prev_alloc=1 */
	PUT(p + 2 * WSIZE, PACK(DSIZE, 1)); /* Prologue footer: size=8, alloc=1 */
	PUT(p + 3 * WSIZE, PACK(0, 3));     /* Epilogue header: size=0, alloc=1, prev_alloc=1 */

	heap_listp = p + 2 * WSIZE;          /* Points to prologue payload */

	/* Extend the empty heap with a free block */
	if (extend_heap(CHUNKSIZE) == NULL)
		return (-1);
	return (0);
}

/*
 * mm_malloc - Allocate a block with at least "size" bytes of payload.
 */
void *
mm_malloc(size_t size)
{
	size_t asize;
	size_t extendsize;
	void *bp;

	if (size == 0)
		return (NULL);

	/* Adjusted block size: payload + header, rounded up to 8-byte alignment */
	asize = (size + WSIZE + (DSIZE - 1)) & ~(size_t)(DSIZE - 1);
	if (asize < MIN_BLOCK)
		asize = MIN_BLOCK;

	/* Search free list for a fit */
	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	/* No fit found — extend heap */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize)) == NULL)
		return (NULL);
	place(bp, asize);
	return (bp);
}

/*
 * mm_free - Free a block.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, GET_PREV_ALLOC(HDRP(bp))));  /* Clear alloc, keep prev_alloc */
	PUT(FTRP(bp), PACK(size, 0));                          /* Write footer */
	coalesce(bp);
}

/*
 * mm_realloc - Reallocate a block with smart in-place expansion.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t asize, oldsize;
	void *next;
	size_t next_size;
	bool next_free;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}
	if (ptr == NULL)
		return (mm_malloc(size));

	asize = (size + WSIZE + (DSIZE - 1)) & ~(size_t)(DSIZE - 1);
	if (asize < MIN_BLOCK)
		asize = MIN_BLOCK;

	oldsize = GET_SIZE(HDRP(ptr));

	/* Current block is already large enough */
	if (oldsize >= asize)
		return (ptr);

	next = NEXT_BLKP(ptr);
	next_size = GET_SIZE(HDRP(next));
	next_free = !GET_ALLOC(HDRP(next));

	/* Case 1: next block is free and combined size is sufficient */
	if (next_free && (oldsize + next_size) >= asize) {
		remove_free(next);
		size_t combined = oldsize + next_size;
		unsigned int flags = GET(HDRP(ptr)) & 0x7;

		if ((combined - asize) >= MIN_BLOCK) {
			/* Split */
			PUT(HDRP(ptr), PACK(asize, flags));
			void *rem = NEXT_BLKP(ptr);
			PUT(HDRP(rem), PACK(combined - asize, 2));   /* prev_alloc=1 */
			PUT(FTRP(rem), PACK(combined - asize, 0));
			insert_free(rem);
			/* Block after remainder already has prev_alloc=0 from when
			 * the original next block was free — remainder is also free. */
		} else {
			/* Use entire combined block */
			PUT(HDRP(ptr), PACK(combined, flags));
			void *after = NEXT_BLKP(ptr);
			PUT(HDRP(after), GET(HDRP(after)) | 0x2);    /* prev_alloc=1 */
		}
		return (ptr);
	}

	/* Case 2: block is at end of heap (next is epilogue) */
	if (next_size == 0) {
		size_t need = asize - oldsize;
		need = (need + (DSIZE - 1)) & ~(size_t)(DSIZE - 1);
		if (mem_sbrk(need) != (void *)-1) {
			unsigned int flags = GET(HDRP(ptr)) & 0x7;
			PUT(HDRP(ptr), PACK(oldsize + need, flags));
			PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 3));       /* New epilogue */
			return (ptr);
		}
	}

	/* Case 3: next is free and block after next is epilogue */
	if (next_free) {
		void *next_next = NEXT_BLKP(next);
		if (GET_SIZE(HDRP(next_next)) == 0) {
			size_t combined = oldsize + next_size;
			size_t need = asize - combined;
			need = (need + (DSIZE - 1)) & ~(size_t)(DSIZE - 1);
			if (mem_sbrk(need) != (void *)-1) {
				remove_free(next);
				unsigned int flags = GET(HDRP(ptr)) & 0x7;
				PUT(HDRP(ptr), PACK(combined + need, flags));
				PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 3));
				return (ptr);
			}
		}
	}

	/* Fall back: malloc + copy + free */
	void *newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);

	size_t copysize = oldsize - WSIZE;   /* Payload of old block */
	if (size < copysize)
		copysize = size;
	memcpy(newptr, ptr, copysize);
	mm_free(ptr);

	return (newptr);
}

/*
 * coalesce - Coalesce a newly freed block with any adjacent free blocks.
 */
static void *
coalesce(void *bp)
{
	size_t size = GET_SIZE(HDRP(bp));
	bool prev_alloc = GET_PREV_ALLOC(HDRP(bp)) != 0;
	bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));

	if (prev_alloc && next_alloc) {
		/* Case 1: nothing to merge */
	} else if (prev_alloc && !next_alloc) {
		/* Case 2: merge with next */
		size += GET_SIZE(HDRP(NEXT_BLKP(bp)));
		remove_free(NEXT_BLKP(bp));
		PUT(HDRP(bp), PACK(size, 2));            /* prev_alloc=1 */
		PUT(FTRP(bp), PACK(size, 0));
	} else if (!prev_alloc && next_alloc) {
		/* Case 3: merge with prev */
		size += GET_SIZE(HDRP(PREV_BLKP(bp)));
		unsigned int pf = GET_PREV_ALLOC(HDRP(PREV_BLKP(bp)));
		remove_free(PREV_BLKP(bp));
		bp = PREV_BLKP(bp);
		PUT(HDRP(bp), PACK(size, pf));
		PUT(FTRP(bp), PACK(size, 0));
	} else {
		/* Case 4: merge with both */
		size += GET_SIZE(HDRP(PREV_BLKP(bp)))
		    + GET_SIZE(HDRP(NEXT_BLKP(bp)));
		unsigned int pf = GET_PREV_ALLOC(HDRP(PREV_BLKP(bp)));
		remove_free(NEXT_BLKP(bp));
		remove_free(PREV_BLKP(bp));
		bp = PREV_BLKP(bp);
		PUT(HDRP(bp), PACK(size, pf));
		PUT(FTRP(bp), PACK(size, 0));
	}

	/* Next block's prev_alloc must be 0 (this block is free) */
	PUT(HDRP(NEXT_BLKP(bp)), GET(HDRP(NEXT_BLKP(bp))) & ~0x2);

	insert_free(bp);
	return (bp);
}

/*
 * extend_heap - Extend the heap by the given number of bytes.
 */
static void *
extend_heap(size_t bytes)
{
	size_t size;
	void *bp;

	/* Round up to 8-byte alignment */
	size = (bytes + (DSIZE - 1)) & ~(size_t)(DSIZE - 1);
	if (size < MIN_BLOCK)
		size = MIN_BLOCK;

	if ((bp = mem_sbrk(size)) == (void *)-1)
		return (NULL);

	/* New block header overwrites old epilogue */
	unsigned int prev_alloc = GET_PREV_ALLOC(HDRP(bp));
	PUT(HDRP(bp), PACK(size, prev_alloc));   /* Free block header */
	PUT(FTRP(bp), PACK(size, 0));            /* Free block footer */
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));   /* New epilogue header */

	return (coalesce(bp));
}

/*
 * find_fit - Find a free block of at least asize bytes.
 *            Best-fit in the matching class; first-fit in larger classes.
 */
static void *
find_fit(size_t asize)
{
	int cls = get_class(asize);
	void *bp;
	void *best = NULL;
	size_t best_size = ~(size_t)0;

	/* Best-fit search in the matching class */
	for (bp = seg_lists[cls]; bp != NULL; bp = NEXT_FREEP(bp)) {
		size_t bsize = GET_SIZE(HDRP(bp));
		if (bsize >= asize) {
			if (bsize == asize)
				return (bp);       /* Perfect fit — return immediately */
			if (bsize < best_size) {
				best = bp;
				best_size = bsize;
			}
		}
	}
	if (best != NULL)
		return (best);

	/* First-fit in larger classes */
	for (int i = cls + 1; i < NUM_CLASSES; i++) {
		if (seg_lists[i] != NULL)
			return (seg_lists[i]);
	}

	return (NULL);
}

/*
 * place - Place a block of asize bytes at bp, splitting if the remainder
 *         is at least MIN_BLOCK bytes.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));
	unsigned int prev_alloc = GET_PREV_ALLOC(HDRP(bp));

	remove_free(bp);

	if ((csize - asize) >= MIN_BLOCK) {
		/* Split: allocate first part, free remainder */
		PUT(HDRP(bp), PACK(asize, prev_alloc | 1));
		void *rem = NEXT_BLKP(bp);
		PUT(HDRP(rem), PACK(csize - asize, 2));     /* prev_alloc=1 */
		PUT(FTRP(rem), PACK(csize - asize, 0));
		insert_free(rem);
	} else {
		/* No split — use entire block */
		PUT(HDRP(bp), PACK(csize, prev_alloc | 1));
		void *next = NEXT_BLKP(bp);
		PUT(HDRP(next), GET(HDRP(next)) | 0x2);     /* Set prev_alloc */
	}
}

/*
 * The remaining routines are heap consistency checker routines.
 */

/*
 * checkblock - Perform a minimal check on the block "bp".
 */
static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % DSIZE)
		printf("Error: %p is not doubleword aligned\n", bp);
	if (!GET_ALLOC(HDRP(bp))) {
		/* Free block: header size should match footer size */
		if (GET_SIZE(HDRP(bp)) != GET_SIZE(FTRP(bp)))
			printf("Error: header size does not match footer size at %p\n",
			    bp);
	}
}

/*
 * checkheap - Perform a minimal check of the heap for consistency.
 */
void
checkheap(bool verbose)
{
	void *bp;
	bool prev_free = false;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	/* Check prologue */
	if (GET_SIZE(HDRP(heap_listp)) != DSIZE ||
	    !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");

	/* Walk heap blocks */
	for (bp = NEXT_BLKP(heap_listp); GET_SIZE(HDRP(bp)) > 0;
	    bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);

		bool is_free = !GET_ALLOC(HDRP(bp));
		if (prev_free && is_free)
			printf("Error: consecutive free blocks at %p\n", bp);
		prev_free = is_free;
	}

	/* Check epilogue */
	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	/* Check free lists */
	for (int i = 0; i < NUM_CLASSES; i++) {
		for (bp = seg_lists[i]; bp != NULL; bp = NEXT_FREEP(bp)) {
			if (GET_ALLOC(HDRP(bp)))
				printf("Error: allocated block %p in free list %d\n",
				    bp, i);
			if (get_class(GET_SIZE(HDRP(bp))) != i)
				printf("Error: block %p in wrong free list class\n",
				    bp);
		}
	}
}

/*
 * printblock - Print the block "bp".
 */
static void
printblock(void *bp)
{
	size_t hsize = GET_SIZE(HDRP(bp));
	bool halloc = GET_ALLOC(HDRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}

	if (halloc) {
		printf("%p: header: [%zu:a] prev_alloc:%d\n", bp, hsize,
		    GET_PREV_ALLOC(HDRP(bp)) != 0);
	} else {
		size_t fsize = GET_SIZE(FTRP(bp));
		printf("%p: header: [%zu:f] footer: [%zu:f] prev_alloc:%d\n",
		    bp, hsize, fsize,
		    GET_PREV_ALLOC(HDRP(bp)) != 0);
	}
}

