/*
 * Segregated free list allocator with:
 * - Boundary tag coalescing with prev_alloc bit optimization
 * - No footers for allocated blocks
 * - 14 segregated free list size classes
 * - Best-fit within class, first-fit in larger classes
 * - Smart realloc with in-place expansion
 * - 8-byte alignment
 *
 * Block layout (64-bit system):
 *   Header: 8 bytes (size | prev_alloc<<1 | alloc)
 *   Payload: variable
 *   Footer: 8 bytes (only for free blocks)
 *
 * Free block minimum: header(8) + next(8) + prev(8) + footer(8) = 32
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

team_t team = {
	"BSCS Bench",
	"BSCS Bench Agent",
	"bscs1",
	"",
	""
};

/* Basic constants */
#define WSIZE       sizeof(void *)  /* Word size (bytes): 8 on 64-bit */
#define DSIZE       (2 * WSIZE)     /* Double word size: 16 */
#define CHUNKSIZE   (1 << 12)       /* Default heap extension: 4096 */
#define MIN_BLOCK   (4 * WSIZE)     /* Minimum block: hdr+next+prev+ftr = 32 */
#define NUM_CLASSES 14              /* Segregated list classes */

#define MAX(x, y)  ((x) > (y) ? (x) : (y))

/* Pack size and flags into a word.  Bit 0 = alloc, Bit 1 = prev_alloc. */
#define PACK(size, flags)  ((size) | (flags))

/* Read / write a word at address p */
#define GET(p)       (*(uintptr_t *)(p))
#define PUT(p, val)  (*(uintptr_t *)(p) = (val))

/* Extract fields */
#define GET_SIZE(p)        (GET(p) & ~(DSIZE - 1))
#define GET_ALLOC(p)       (GET(p) & 0x1)
#define GET_PREV_ALLOC(p)  (GET(p) & 0x2)

/* Header / footer from block pointer bp */
#define HDRP(bp)  ((char *)(bp) - WSIZE)
#define FTRP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Next / previous block */
#define NEXT_BLKP(bp)  ((char *)(bp) + GET_SIZE(((char *)(bp) - WSIZE)))
#define PREV_BLKP(bp)  ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Free list pointers in payload area */
#define NEXT_FREEP(bp)  (*(void **)(bp))
#define PREV_FREEP(bp)  (*(void **)((char *)(bp) + WSIZE))

/* Globals */
static char *heap_listp;
static void **seg_lists;  /* Array of NUM_CLASSES heads, stored in heap */

/* Prototypes */
static void *coalesce(void *bp);
static void *extend_heap(size_t words);
static void *find_fit(size_t asize);
static void *place(void *bp, size_t asize);
static void  insert_free(void *bp);
static void  remove_free(void *bp);
static int   get_class(size_t size);

static void  checkblock(void *bp);
void         checkheap(bool verbose);
static void  printblock(void *bp);

/*
 * get_class - segregated list index for a block size
 */
static int
get_class(size_t size)
{
	if (size <= 32)     return 0;
	if (size <= 64)     return 1;
	if (size <= 128)    return 2;
	if (size <= 256)    return 3;
	if (size <= 512)    return 4;
	if (size <= 1024)   return 5;
	if (size <= 2048)   return 6;
	if (size <= 4096)   return 7;
	if (size <= 8192)   return 8;
	if (size <= 16384)  return 9;
	if (size <= 32768)  return 10;
	if (size <= 65536)  return 11;
	if (size <= 131072) return 12;
	return 13;
}

/*
 * insert_free - LIFO insert into segregated list
 */
static void
insert_free(void *bp)
{
	int cls = get_class(GET_SIZE(HDRP(bp)));
	void *head = seg_lists[cls];

	NEXT_FREEP(bp) = head;
	PREV_FREEP(bp) = NULL;
	if (head != NULL)
		PREV_FREEP(head) = bp;
	seg_lists[cls] = bp;
}

/*
 * remove_free - remove block from its segregated list
 */
static void
remove_free(void *bp)
{
	int cls = get_class(GET_SIZE(HDRP(bp)));
	void *prev = PREV_FREEP(bp);
	void *next = NEXT_FREEP(bp);

	if (prev != NULL)
		NEXT_FREEP(prev) = next;
	else
		seg_lists[cls] = next;
	if (next != NULL)
		PREV_FREEP(next) = prev;
}

/*
 * mm_init - Initialize the memory manager.
 */
int
mm_init(void)
{
	size_t heads_bytes = NUM_CLASSES * WSIZE;
	/* heads + pad + prologue_hdr + prologue_ftr + epilogue_hdr */
	size_t init_words = (heads_bytes / WSIZE) + 4;
	char *start;

	if ((start = mem_sbrk(init_words * WSIZE)) == (void *)-1)
		return (-1);

	seg_lists = (void **)start;
	for (int i = 0; i < NUM_CLASSES; i++)
		seg_lists[i] = NULL;

	char *p = start + heads_bytes;
	PUT(p, 0);                            /* Alignment padding */
	PUT(p + (1 * WSIZE), PACK(DSIZE, 3)); /* Prologue header */
	PUT(p + (2 * WSIZE), PACK(DSIZE, 3)); /* Prologue footer */
	PUT(p + (3 * WSIZE), PACK(0, 3));     /* Epilogue header */
	heap_listp = p + (2 * WSIZE);

	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return (-1);
	return (0);
}

/*
 * mm_malloc - Allocate a block with at least "size" bytes of payload.
 */
void *
mm_malloc(size_t size)
{
	size_t asize, extendsize;
	void *bp;

	if (size == 0)
		return (NULL);

	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + WSIZE + (DSIZE - 1)) / DSIZE);
	if (asize < MIN_BLOCK)
		asize = MIN_BLOCK;

	if ((bp = find_fit(asize)) != NULL)
		return (place(bp, asize));

	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)
		return (NULL);
	return (place(bp, asize));
}

/*
 * mm_free - Free a block.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, GET_PREV_ALLOC(HDRP(bp))));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * mm_realloc - Smart realloc with in-place expansion.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t asize, oldsize, next_size, combined;
	void *next;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}
	if (ptr == NULL)
		return (mm_malloc(size));

	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + WSIZE + (DSIZE - 1)) / DSIZE);
	if (asize < MIN_BLOCK)
		asize = MIN_BLOCK;

	oldsize = GET_SIZE(HDRP(ptr));
	if (oldsize >= asize)
		return (ptr);

	next = NEXT_BLKP(ptr);
	next_size = GET_SIZE(HDRP(next));

	/* Case 1: next block is free and combined size suffices */
	if (!GET_ALLOC(HDRP(next)) && (oldsize + next_size) >= asize) {
		remove_free(next);
		combined = oldsize + next_size;
		PUT(HDRP(ptr), PACK(combined, GET(HDRP(ptr)) & 0x7));

		if ((combined - asize) >= MIN_BLOCK) {
			PUT(HDRP(ptr), PACK(asize, GET(HDRP(ptr)) & 0x7));
			void *rem = NEXT_BLKP(ptr);
			PUT(HDRP(rem), PACK(combined - asize, 2));
			PUT(FTRP(rem), PACK(combined - asize, 0));
			insert_free(rem);
			/* Ensure block after remainder knows prev is free */
			void *after_rem = NEXT_BLKP(rem);
			PUT(HDRP(after_rem), GET(HDRP(after_rem)) & ~(uintptr_t)0x2);
		} else {
			void *after = NEXT_BLKP(ptr);
			PUT(HDRP(after), GET(HDRP(after)) | 0x2);
		}
		return (ptr);
	}

	/* Case 2: at end of heap (next is epilogue) */
	if (next_size == 0) {
		size_t need = asize - oldsize;
		if ((need % DSIZE) != 0)
			need = DSIZE * ((need + DSIZE - 1) / DSIZE);
		if (mem_sbrk(need) != (void *)-1) {
			PUT(HDRP(ptr), PACK(oldsize + need, GET(HDRP(ptr)) & 0x7));
			PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 3));
			return (ptr);
		}
	}

	/* Case 3: next is free + next-next is epilogue */
	if (!GET_ALLOC(HDRP(next)) && GET_SIZE(HDRP(NEXT_BLKP(next))) == 0) {
		combined = oldsize + next_size;
		size_t need = asize - combined;
		if ((need % DSIZE) != 0)
			need = DSIZE * ((need + DSIZE - 1) / DSIZE);
		if (mem_sbrk(need) != (void *)-1) {
			remove_free(next);
			PUT(HDRP(ptr), PACK(combined + need,
			    GET(HDRP(ptr)) & 0x7));
			PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 3));
			return (ptr);
		}
	}

	/* Fallback: malloc + copy + free */
	void *newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);

	size_t copysize = oldsize - WSIZE;
	if (size < copysize)
		copysize = size;
	memcpy(newptr, ptr, copysize);
	mm_free(ptr);
	return (newptr);
}

/*
 * coalesce - Boundary tag coalescing.
 */
static void *
coalesce(void *bp)
{
	size_t size = GET_SIZE(HDRP(bp));
	bool prev_alloc = GET_PREV_ALLOC(HDRP(bp)) != 0;
	bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));

	if (prev_alloc && next_alloc) {
		/* Case 1 */
	} else if (prev_alloc && !next_alloc) {
		/* Case 2: merge with next */
		size += GET_SIZE(HDRP(NEXT_BLKP(bp)));
		remove_free(NEXT_BLKP(bp));
		PUT(HDRP(bp), PACK(size, 2));
		PUT(FTRP(bp), PACK(size, 0));
	} else if (!prev_alloc && next_alloc) {
		/* Case 3: merge with prev */
		size += GET_SIZE(HDRP(PREV_BLKP(bp)));
		uintptr_t pf = GET_PREV_ALLOC(HDRP(PREV_BLKP(bp)));
		remove_free(PREV_BLKP(bp));
		bp = PREV_BLKP(bp);
		PUT(HDRP(bp), PACK(size, pf));
		PUT(FTRP(bp), PACK(size, 0));
	} else {
		/* Case 4: merge with both */
		size += GET_SIZE(HDRP(PREV_BLKP(bp)))
		    + GET_SIZE(HDRP(NEXT_BLKP(bp)));
		uintptr_t pf = GET_PREV_ALLOC(HDRP(PREV_BLKP(bp)));
		remove_free(NEXT_BLKP(bp));
		remove_free(PREV_BLKP(bp));
		bp = PREV_BLKP(bp);
		PUT(HDRP(bp), PACK(size, pf));
		PUT(FTRP(bp), PACK(size, 0));
	}

	/* Update next block's prev_alloc to 0 (this block is free) */
	PUT(HDRP(NEXT_BLKP(bp)), GET(HDRP(NEXT_BLKP(bp))) & ~(uintptr_t)0x2);

	insert_free(bp);
	return (bp);
}

/*
 * extend_heap - Extend the heap by "words" words.
 */
static void *
extend_heap(size_t words)
{
	size_t size;
	void *bp;

	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if (size < MIN_BLOCK)
		size = MIN_BLOCK;

	if ((bp = mem_sbrk(size)) == (void *)-1)
		return (NULL);

	PUT(HDRP(bp), PACK(size, GET_PREV_ALLOC(HDRP(bp))));
	PUT(FTRP(bp), PACK(size, 0));
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));

	return (coalesce(bp));
}

/*
 * find_fit - Best-fit in matching class, first-fit in larger classes.
 */
static void *
find_fit(size_t asize)
{
	int cls = get_class(asize);
	void *bp, *best = NULL;
	size_t best_size = ~(size_t)0;

	for (bp = seg_lists[cls]; bp != NULL; bp = NEXT_FREEP(bp)) {
		size_t bsize = GET_SIZE(HDRP(bp));
		if (bsize >= asize) {
			if (bsize == asize)
				return (bp);
			if (bsize < best_size) {
				best = bp;
				best_size = bsize;
			}
		}
	}
	if (best != NULL)
		return (best);

	for (int i = cls + 1; i < NUM_CLASSES; i++) {
		if (seg_lists[i] != NULL)
			return (seg_lists[i]);
	}
	return (NULL);
}

/*
 * place - Place asize block at bp, split if possible.  Returns bp
 *         of the allocated block (may differ from input when placing
 *         large blocks at end of free region).
 */
static void *
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));
	uintptr_t prev_alloc = GET_PREV_ALLOC(HDRP(bp));

	remove_free(bp);

	if ((csize - asize) >= MIN_BLOCK) {
		if (asize >= 96) {
			/* Large request: place at END of free block so the
			 * allocated block is closer to the heap top, enabling
			 * future in-place realloc expansions. */
			PUT(HDRP(bp), PACK(csize - asize, prev_alloc));
			PUT(FTRP(bp), PACK(csize - asize, 0));
			insert_free(bp);
			bp = NEXT_BLKP(bp);
			PUT(HDRP(bp), PACK(asize, 1));  /* prev is free */
			/* Next block's prev_alloc: was 0 (original was free),
			 * now the allocated block is here, so set to 1 */
			void *nb = NEXT_BLKP(bp);
			PUT(HDRP(nb), GET(HDRP(nb)) | 0x2);
		} else {
			/* Small request: place at START */
			PUT(HDRP(bp), PACK(asize, prev_alloc | 1));
			void *rem = NEXT_BLKP(bp);
			PUT(HDRP(rem), PACK(csize - asize, 2));
			PUT(FTRP(rem), PACK(csize - asize, 0));
			insert_free(rem);
			/* Block after remainder: clear prev_alloc (rem is free) */
			void *after_rem = NEXT_BLKP(rem);
			PUT(HDRP(after_rem),
			    GET(HDRP(after_rem)) & ~(uintptr_t)0x2);
		}
	} else {
		PUT(HDRP(bp), PACK(csize, prev_alloc | 1));
		void *nb = NEXT_BLKP(bp);
		PUT(HDRP(nb), GET(HDRP(nb)) | 0x2);
	}
	return (bp);
}

/* ---------------------------------------------------------------
 * Heap consistency checker
 * --------------------------------------------------------------- */
static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % DSIZE)
		printf("Error: %p is not doubleword aligned\n", bp);
	if (!GET_ALLOC(HDRP(bp))) {
		if (GET(HDRP(bp)) != GET(FTRP(bp)))
			printf("Error: header != footer at %p\n", bp);
	}
}

void
checkheap(bool verbose)
{
	void *bp;
	bool prev_free = false;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE ||
	    !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	for (bp = NEXT_BLKP(heap_listp); GET_SIZE(HDRP(bp)) > 0;
	    bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
		if (prev_free && !GET_ALLOC(HDRP(bp)))
			printf("Consecutive free blocks at %p\n", bp);
		prev_free = !GET_ALLOC(HDRP(bp));
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	for (int i = 0; i < NUM_CLASSES; i++) {
		for (bp = seg_lists[i]; bp != NULL; bp = NEXT_FREEP(bp)) {
			if (GET_ALLOC(HDRP(bp)))
				printf("Alloc block %p in free list %d\n",
				    bp, i);
		}
	}
}

static void
printblock(void *bp)
{
	size_t hsize = GET_SIZE(HDRP(bp));
	bool halloc = GET_ALLOC(HDRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}
	if (halloc) {
		printf("%p: header: [%zu:a] pa:%d\n", bp, hsize,
		    GET_PREV_ALLOC(HDRP(bp)) != 0);
	} else {
		size_t fsize = GET_SIZE(FTRP(bp));
		printf("%p: header: [%zu:f] footer: [%zu:f] pa:%d\n",
		    bp, hsize, fsize, GET_PREV_ALLOC(HDRP(bp)) != 0);
	}
}

